    /// Returns (glyph string for sketchybar-app-font, brand color) for a given app name.
    /// Falls back to prefix match for names like 'Adobe Bridge CC'.
    public static func lookup(appName: String) -> (glyph: String, color: CGColor) {
        if let entry = map[appName] { return entry }
        for (key, val) in map {
            if appName.hasPrefix(key) { return val }
        }
        // Default: lavender color, no glyph
        return ("", CGColor(red: 0.867, green: 0.714, blue: 0.949, alpha: 1.0))
    }
